/*
 * 		자바 => 모든 소스는 클래스 안에 첨부
 * 			=> JVM이 가장 먼저 실행하는 부분 => main (진입점)
 * 		이미 만들어진 클래스(개발자가 만들거나 Java가 제공한) 읽기 -> import 키워드 사용
 * 		
 * 		package
 * 		import
 * 		public class ClassName {
 * 			
 * 		}
 * 
 * 		main 함수에서 static 을 삭제하면 main 함수 인식 안 됨
 * 		하지만 public 과 static 의 위치를 바꾸는것은 가능
 * 		매개변수의 이름을 임의로 바꾸는것도 가능
 */
public class 자바_시작 {

	static public void main(String[] a) {
		// TODO Auto-generated method stub
		System.out.println("Hello Java");
	}

}
